    def build_nav(self) -> ft.Control:
        tabs = [
            ("executivo", "Grupo Executivo", ft.Icons.DASHBOARD_ROUNDED),
            ("matriz", "Revenda Matriz", ft.Icons.STORE_ROUNDED),
            ("filial", "Filial Industrial", ft.Icons.FACTORY_ROUNDED),
            ("multi", "Multi Simples", ft.Icons.ACCOUNT_BALANCE_ROUNDED),
            ("dados", "Dados Base", ft.Icons.TABLE_ROWS_ROUNDED),
        ]
        buttons = []
        for key, label, icon in tabs:
            selected = self.current_tab == key
            buttons.append(
                ft.TextButton(
                    content=ft.Row(
                        spacing=8,
                        controls=[
                            ft.Icon(icon, color=PRIMARY if selected else MUTED, size=20),
                            ft.Text(label, color=PRIMARY if selected else "#374151", weight=ft.FontWeight.W_600 if selected else ft.FontWeight.W_500),
                        ],
                    ),
                    style=ft.ButtonStyle(
                        bgcolor=SOFT_BLUE if selected else CARD,
                        shape=ft.RoundedRectangleBorder(radius=18),
                        padding=ft.Padding.symmetric(horizontal=16, vertical=14),
                    ),
                    on_click=lambda e, tab=key: self.set_tab(tab),
                )
            )
        return ft.Container(
            margin=ft.Margin(left=20, right=20, top=0, bottom=0),
            content=ft.Row(wrap=True, spacing=10, controls=buttons),
        )

    def build_tab_content(self) -> ft.Control:
        if self.current_tab == "matriz":
            return self.build_matriz_tab()
        if self.current_tab == "filial":
            return self.build_filial_tab()
        if self.current_tab == "multi":
            return self.build_multi_tab()
        if self.current_tab == "dados":
            return self.build_dados_tab()
        return self.build_executivo_tab()

    def card(self, title: str, value: str, subtitle: str = "", tone: str = CARD, width: int | None = None) -> ft.Control:
        return ft.Container(
            width=width,
            padding=ft.Padding.all(18),
            bgcolor=tone,
            border_radius=24,
            shadow=[ft.BoxShadow(blur_radius=16, color=ft.Colors.with_opacity(0.07, ft.Colors.BLACK), offset=ft.Offset(0, 8))],
            content=ft.Column(
                spacing=8,
                controls=[
                    ft.Text(title, size=13, color=MUTED, weight=ft.FontWeight.W_600),
                    ft.Text(value, size=20, color=INK, weight=ft.FontWeight.BOLD),
                    ft.Text(subtitle, size=12, color=MUTED),
                ],
            ),
        )

    def section_card(self, title: str, content: ft.Control, subtitle: str = "") -> ft.Control:
        children = [ft.Text(title, size=16, weight=ft.FontWeight.BOLD, color=INK)]
        if subtitle:
            children.append(ft.Text(subtitle, size=12, color=MUTED))
        children.append(content)
        return ft.Container(
            padding=ft.Padding.all(18),
            bgcolor=CARD,
            border_radius=26,
            shadow=[ft.BoxShadow(blur_radius=16, color=ft.Colors.with_opacity(0.07, ft.Colors.BLACK), offset=ft.Offset(0, 8))],
            content=ft.Column(spacing=12, controls=children),
        )

