    def slider_card(self, title: str, value: float, minimum: float, maximum: float, step: float, callback, note: str, suffix: str = "") -> ft.Control:
        divisions = int(round((maximum - minimum) / step)) if step else None
        label_value = f"{value:.2f}{suffix}".replace(".", ",") if suffix else br_money(value)
        return ft.Container(
            padding=ft.Padding.all(16),
            bgcolor=CARD,
            border_radius=22,
            content=ft.Column(
                spacing=8,
                controls=[
                    ft.Row(
                        alignment=ft.MainAxisAlignment.SPACE_BETWEEN,
                        controls=[
                            ft.Text(title, size=14, weight=ft.FontWeight.W_600),
                            ft.Text(label_value, size=13, color=PRIMARY_DARK, weight=ft.FontWeight.W_600),
                        ],
                    ),
                    ft.Slider(
                        min=minimum,
                        max=maximum,
                        value=value,
                        divisions=divisions,
                        active_color=PRIMARY_DARK,
                        inactive_color="#CBD5E1",
                        on_change=lambda e: callback(float(e.control.value)),
                    ),
                    ft.Text(note, size=12, color=MUTED),
                ],
            ),
        )

    def update_numeric(self, field: str, value: float):
        if field == "matrix_faturamento":
            self.matrix.faturamento = value
        elif field == "matrix_cmv_pct":
            self.matrix.cmv_pct = value
        elif field == "matrix_credito_icms_pct":
            self.matrix.credito_icms_pct = value
        elif field == "matrix_share_ferragens_pct":
            self.matrix.share_ferragens_pct = value
        elif field == "filial_faturamento":
            self.filial.faturamento = value
        elif field == "multi_receita_extra":
            self.multi.receita_extra = value
        self.render()

